  // ----------------------------------------------------------------------
  // LsqEnqCtrl power-up X alignment.
  //   LsqEnqCtrl (golden black box, instantiated identically on both sides)
  //   has 4 control regs (t1_redirect/t2_redirect/t3_update/io_enq_canAccept_REG)
  //   that are driven by `always @(posedge clock)` with NO reset and NO
  //   RANDOMIZE_REG_INIT under the UT compile (+define+SYNTHESIS only).
  //   They start X; t3_update=X then corrupts the (otherwise reset) lqCounter
  //   /sqCounter to X via `if (t3_update)` on the first clock, and the X
  //   silently propagates until a cycle where it flips a pointer update,
  //   producing the lqIdx/sqIdx g/i mismatch. In real silicon these regs
  //   settle to 0 (redirect held low across cold reset). We initialize both
  //   instances' un-reset regs to that settled 0 value once at t=0 — same fix
  //   used for the two PtwCache SRAMs in L2TLB. This is a power-up alignment,
  //   not a continuous force, so functional behavior is untouched.
  // NewDispatch core no-reset power-up X alignment.
  //   uopSelIQ_<i>_<q> (the IQ routing matrix) and conserveFlowTotal_<i> are
  //   `always @(posedge clock)` regs with NO reset and no RANDOMIZE under the UT
  //   compile, so they power up X (in BOTH instances — same source). uopSelIQ
  //   entries not written by a toRenameAllFire / cleared by firedVec keep that X
  //   for a long time, then surface (resolving differently per instance) as an
  //   io_toIssueQueues_*_valid g/i mismatch millions of cycles in. Real silicon
  //   settles these to 0 (no uop selected before the first dispatch). We align
  //   the power-up state of both instances to that settled 0 — same approach as
  //   the two PtwCache SRAMs in L2TLB. Kept in the tb (not the RTL) so the
  //   rewrite stays formally equivalent to golden (golden has no reset on these).
  //   force/release is used for the rewrite side because its always_ff drivers
  //   forbid a procedural blocking assignment (ICPD); golden's plain always
  //   blocks accept a one-shot blocking init.
  initial begin
    // hold both instances' un-reset regs at the settled cold value through reset
`include "tb_golden_uopseliq_init.svh"
`include "tb_impl_uopseliq_force.svh"
    @(negedge rst);  // release at end of reset so normal operation is untouched
`include "tb_impl_uopseliq_release.svh"
  end
  // LsqEnqCtrl is the same golden black box on both sides (plain always blocks),
  // so a one-shot blocking init at t=0 is accepted for both; see the t3_update X
  // analysis above.
  initial begin
    u_g.lsqEnqCtrl.t1_redirect          = 1'b0;
    u_g.lsqEnqCtrl.t2_redirect          = 1'b0;
    u_g.lsqEnqCtrl.t3_update            = 1'b0;
    u_g.lsqEnqCtrl.io_enq_canAccept_REG = 1'b0;
    u_i.u_core.lsqEnqCtrl.t1_redirect          = 1'b0;
    u_i.u_core.lsqEnqCtrl.t2_redirect          = 1'b0;
    u_i.u_core.lsqEnqCtrl.t3_update            = 1'b0;
    u_i.u_core.lsqEnqCtrl.io_enq_canAccept_REG = 1'b0;
  end
  initial begin
    rst = 1; repeat (16) @(posedge clk); rst = 0;
    repeat (NCYCLES) @(posedge clk);
    $display("checks=%0d errors=%0d", checks, errors);
    if (errors == 0 && checks > 1000) $display("TEST PASSED"); else $display("TEST FAILED");
    $finish;
  end
endmodule
